import{_ as e,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":null}'),l={name:"glossary.md"};function n(i,a,h,d,s,c){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><h2 id="base-model" tabindex="-1">Base Model <a class="header-anchor" href="#base-model" aria-label="Permalink to &quot;Base Model&quot;">​</a></h2><p>基础模型。常用于说明 checkpoint 或 LoRA 基于哪个生态训练，例如 SD1.5、SDXL、Pony、FLUX。</p><h2 id="checkpoint" tabindex="-1">Checkpoint <a class="header-anchor" href="#checkpoint" aria-label="Permalink to &quot;Checkpoint&quot;">​</a></h2><p>保存模型权重的文件。AI 绘画里常见扩展名是 <code>.safetensors</code> 或 <code>.ckpt</code>。</p><h2 id="cfg" tabindex="-1">CFG <a class="header-anchor" href="#cfg" aria-label="Permalink to &quot;CFG&quot;">​</a></h2><p>提示词引导强度。数值越高不代表越好，过高可能让画面变硬、变脏或结构异常。</p><h2 id="clip" tabindex="-1">CLIP <a class="header-anchor" href="#clip" aria-label="Permalink to &quot;CLIP&quot;">​</a></h2><p>常见文本/图像编码模型。在 AI 绘画中经常负责把提示词编码成模型可用的信息。</p><h2 id="controlnet" tabindex="-1">ControlNet <a class="header-anchor" href="#controlnet" aria-label="Permalink to &quot;ControlNet&quot;">​</a></h2><p>结构控制模块，可以用姿势、线稿、深度图等条件控制生成结果。</p><h2 id="denoise" tabindex="-1">Denoise <a class="header-anchor" href="#denoise" aria-label="Permalink to &quot;Denoise&quot;">​</a></h2><p>去噪强度。在图生图和局部重绘中常见。数值越高，改动越大。</p><h2 id="embedding" tabindex="-1">Embedding <a class="header-anchor" href="#embedding" aria-label="Permalink to &quot;Embedding&quot;">​</a></h2><p>也叫 Textual Inversion。是一种小型提示词嵌入，用来触发特定概念或改善负面效果。</p><h2 id="latent" tabindex="-1">Latent <a class="header-anchor" href="#latent" aria-label="Permalink to &quot;Latent&quot;">​</a></h2><p>模型内部的压缩图像表示。扩散模型常在 latent 空间里生成，再通过 VAE 解码成图片。</p><h2 id="lora" tabindex="-1">LoRA <a class="header-anchor" href="#lora" aria-label="Permalink to &quot;LoRA&quot;">​</a></h2><p>低秩适配模型。用于给底模追加角色、画风、服装、姿势或概念。</p><h2 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h2><p>提示词。分为正向提示词和负向提示词。</p><h2 id="sampler" tabindex="-1">Sampler <a class="header-anchor" href="#sampler" aria-label="Permalink to &quot;Sampler&quot;">​</a></h2><p>采样器，控制扩散模型去噪时的算法路径。</p><h2 id="scheduler" tabindex="-1">Scheduler <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;Scheduler&quot;">​</a></h2><p>调度器，控制去噪过程中噪声强度的变化方式。</p><h2 id="seed" tabindex="-1">Seed <a class="header-anchor" href="#seed" aria-label="Permalink to &quot;Seed&quot;">​</a></h2><p>随机种子。固定 seed 可以复现相近结果，便于比较参数。</p><h2 id="text-encoder" tabindex="-1">Text Encoder <a class="header-anchor" href="#text-encoder" aria-label="Permalink to &quot;Text Encoder&quot;">​</a></h2><p>文本编码器，把提示词转换成模型可以理解的数字表示。</p><h2 id="vae" tabindex="-1">VAE <a class="header-anchor" href="#vae" aria-label="Permalink to &quot;VAE&quot;">​</a></h2><p>变分自编码器。负责在 latent 和最终图片之间转换。</p><h2 id="webui" tabindex="-1">WebUI <a class="header-anchor" href="#webui" aria-label="Permalink to &quot;WebUI&quot;">​</a></h2><p>AI 绘画图形界面。常用于指 Stable Diffusion WebUI，也可以泛指浏览器里的本地绘图界面。</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><p>工作流。把模型、提示词、采样器、VAE、LoRA、ControlNet 等节点连接起来的执行流程。</p>',35)])])}const b=e(l,[["render",n]]);export{u as __pageData,b as default};
